CREATE TABLE IF NOT EXISTS valora.certificates (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid REFERENCES valora.organizations(id), response_id uuid NOT NULL REFERENCES valora.responses(id), certificate_code text NOT NULL UNIQUE, participant_name text, issuer_name text, survey_name text, score_label text, maturity_label text, pdf_path text, png_path text, validation_url text, issued_at timestamptz NOT NULL DEFAULT now(), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), created_by uuid, updated_by uuid, is_deleted boolean NOT NULL DEFAULT false);
